            LOGGER.log(Level.INFO, "Successfully read file: {0}, size: {1} bytes", 
                    new Object[]{targetPath, Files.size(targetPath)});
            return content;
        } catch (IOException e) {
            LOGGER.log(Level.SEVERE, "Failed to read file: " + targetPath, e);
            throw new IOException("Failed to read file: " + filePath, e);
        }
    }
}
